parameters.jsCode:
const response = $input.first().json;
const content = response.choices[0].message.content;
const triggerData = $('When Called By WF-0').first().json;

let parsed;
try {
  const clean = content.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  throw new Error('Erreur parsing DeepSeek: ' + content.substring(0, 200));
}

if (!parsed.message_valide || parsed.action !== 'planifier_appel') {
  return [{ json: { action: 'non_reconnu', chat_id: String(triggerData.chat_id || '') } }];
}

const dateAppel = new Date(parsed.date_appel_iso);
if (isNaN(dateAppel.getTime())) {
  throw new Error('Date invalide: ' + parsed.date_appel_iso);
}
if (dateAppel < new Date()) {
  throw new Error('La date de l\'appel est dans le passé: ' + parsed.date_appel_iso);
}

const dateFin = new Date(dateAppel.getTime() + (parsed.duree_minutes || 30) * 60000);

return [{
  json: {
    action: 'planifier_appel',
    chat_id: String(triggerData.chat_id || ''),
    prospect_id: parsed.prospect_id || null,
    prospect_nom: parsed.prospect_nom || 'Prospect',
    date_appel_iso: dateAppel.toISOString(),
    date_fin_iso: dateFin.toISOString(),
    date_appel_affichage: dateAppel.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' }),
    heure_affichage: dateAppel.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }),
    duree_minutes: parsed.duree_minutes || 30,
    notes_appel: parsed.notes_appel || null
  }
}];

