parameters.jsCode:
const now = new Date();
const items = $input.all();
const rappelsAEnvoyer = [];

for (const item of items) {
  const a = item.json;
  const dateAppel = new Date(a.date_appel);
  const diffMs = dateAppel.getTime() - now.getTime();
  const diffMin = diffMs / 60000;

  if (diffMin >= 175 && diffMin <= 185 && !a.rappel_3h_envoye) {
    rappelsAEnvoyer.push({ json: { ...a, type_rappel: '3h', emoji: '⏰', message_rappel: 'dans 3 heures' } });
  } else if (diffMin >= 55 && diffMin <= 65 && !a.rappel_1h_envoye) {
    rappelsAEnvoyer.push({ json: { ...a, type_rappel: '1h', emoji: '🔔', message_rappel: 'dans 1 heure' } });
  } else if (diffMin >= 25 && diffMin <= 35 && !a.rappel_30min_envoye) {
    rappelsAEnvoyer.push({ json: { ...a, type_rappel: '30min', emoji: '🚨', message_rappel: 'dans 30 minutes' } });
  } else if (diffMin >= -5 && diffMin <= 5 && !a.rappel_heure_envoye) {
    rappelsAEnvoyer.push({ json: { ...a, type_rappel: 'heure_h', emoji: '📞', message_rappel: "C'EST L'HEURE !" } });
  }
}

return rappelsAEnvoyer.length > 0 ? rappelsAEnvoyer : [];

