={{ 
  const a = $json;
  const dateAppel = new Date(a.date_appel);
  const heure = dateAppel.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });

  let msg = a.emoji + ' *Rappel appel — ' + a.message_rappel + '*\n\n';
  msg += '📞 *Prospect :* ' + a.prospect_nom + '\n';
  msg += '🕐 *Heure :* ' + heure + '\n';
  if (a.email) msg += '📧 *Email :* ' + a.email + '\n';
  if (a.telephone) msg += '📞 *Tél :* ' + a.telephone + '\n';
  if (a.linkedin_url) msg += '🔗 *LinkedIn :* ' + a.linkedin_url + '\n';
  if (a.secteur) msg += '🏭 *Secteur :* ' + a.secteur + '\n';
  if (a.score_pertinence) msg += '⭐ *Score :* ' + a.score_pertinence + '/10\n';
  if (a.type_rappel === 'heure_h') {
    msg += '\n📋 *Profil :*\n';
    msg += (a.description || 'Aucune description').substring(0, 400) + '\n';
    if (a.notes) msg += '\n📝 *Notes :* ' + a.notes;
  }
  return msg;
}}

